// src/components/DiscountChart.js
import React, { useEffect, useState } from 'react';
import { supabase } from './supabaseClient'; // Ensure supabaseClient.js is set up correctly
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';

function DiscountChart() {
  const [data, setData] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      const { data, error } = await supabase
        .from('PLS - DiscountCharts') // Your table name
        .select('*');

      if (error) {
        console.error('Error fetching data:', error);
      } else {
        // Format data if necessary
        const formattedData = data.map((item) => ({
          day: item.Day, // Use the correct field name
          discount: parseFloat(item['Discount/Premium']), // Use the correct field name
          backingValue: parseFloat(item['Backing Value']), // Use the correct field name
        }));
        setData(formattedData);
      }
    };

    fetchData();
  }, []);

  return (
    <ResponsiveContainer width="100%" height={400}>
      <LineChart
        width={800}
        height={400}
        data={data}
        margin={{ top: 5, right: 30, left: 20, bottom: 5 }}
      >
        <CartesianGrid strokeDasharray="3 3" />
        <XAxis dataKey="day" />
        <YAxis />
        <Tooltip />
        <Legend />
        <Line type="monotone" dataKey="discount" stroke="#FF0000" name="Δ Discount/Premium in HEX" />
        <Line type="monotone" dataKey="backingValue" stroke="#FFD700" name="Backing Value (Principle + Yield)" />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default DiscountChart;
